<script>

function btnCommProfile_Click() {
	writeToLogTable("Click", "btnCommProfile");
}

{% if sqUsingApprovals == true %}
	// todo8: using approvals: YES

	// BULK APPROVAL HELPER FUNCTIONS

	// Parse userLoanOfficerList into array of officer objects
	function parseUserLoanOfficerList() {
		const userPermissionList = "{{userLoanOfficerList}}";


		if (!userPermissionList || userPermissionList.trim() === '' || userPermissionList === '|') {
			return [];
		}

		const officers = [];
		// Format is "|name|code|name|code|" - split and group pairs
		const parts = userPermissionList.split('|').filter(part => part.trim() !== '');

		for (let i = 0; i < parts.length; i += 2) {
			if (i + 1 < parts.length) {
				const name = parts[i];
				const code = parts[i + 1];

				officers.push({
					name: name,
					code: code
				});
			}
		}

			return officers;
	}

	// Get commission total for a specific officer using pre-calculated server-side data
	function getOfficerCommissionTotal(officerCode) {

		// Use the pre-calculated data from server
		if (window.bulkApprovalOfficerData) {
			const officerData = window.bulkApprovalOfficerData.find(officer => officer.code === officerCode);
			if (officerData) {
				const formattedTotal = new Intl.NumberFormat('en-US', {
					style: 'currency',
					currency: 'USD'
				}).format(officerData.total);


				return {
					total: officerData.total,
					formattedTotal: formattedTotal,
					recordCount: officerData.count
				};
			}
		}

			return {
			total: 0,
			formattedTotal: '$0.00',
			recordCount: 0
		};
	}

	// APPROVAL CHECKING
	async function checkSophisticatedApprovalStatus(officerIdentifier, periodNo, useOfficerCode = true) {
		try {
			const approvalType = "{{sqApprovalType}}";
			const viewMode = window.APPROVAL_VIEW_MODE;
			const allowAction = window.ALLOW_APPROVAL_ACTION;
			const loanOfficerName = window.LOAN_OFFICER_NAME;
			const isBranchManager = window.IS_BRANCH_MANAGER;
			const isOwnCommissions = window.IS_OWN_COMMISSIONS;

			// Build filter expression based on whether we have code or ID
			let filterExpr;
			if (useOfficerCode) {
				filterExpr = `$filter=lv_loanofficercode eq '${officerIdentifier}' and lv_periodno eq ${periodNo}`;
			} else {
				filterExpr = `$filter=lv_loanofficer eq '${officerIdentifier}' and lv_periodno eq ${periodNo}`;
			}

			const approvalRecords = await apiGetRecords("lv_lvcompcommissionapprovals", filterExpr);

			if (!approvalRecords || !Array.isArray(approvalRecords)) {
				console.log('APPROVAL: No records found');
				return {
					showApprovalComplete: false,
					showApprovalRequired: false,
					showViewOnly: false,
					message: 'Error loading approval status'
				};
			}

			// Separate approval records by role
			const bmApprovals = approvalRecords.filter(rec => rec.lv_webrole === 'Branch Manager');
			const loApprovals = approvalRecords.filter(rec => rec.lv_webrole === 'Loan Officer');

			// Apply sophisticated logic based on view mode
			switch (viewMode) {
				case "none":
					return { showApprovalComplete: false, showApprovalRequired: false, showViewOnly: false };

				case "loan_officer_own":
					// "LoanOfficer" config - LO viewing their own
					if (loApprovals.length > 0) {
						const personalizedMessage = formatPersonalizedApprovalMessage(
							loApprovals[0].lv_fullname,
							loApprovals[0].lv_emailaddress,
							window.PAGE_USEREMAIL,
							loApprovals[0].createdon
						);
						return {
							showApprovalComplete: true,
							message: personalizedMessage
						};
					} else {
						return {
							showApprovalRequired: true,
							showApprovalButton: true,
							message: "If you are satisfied with this commission report, click here to finalize and approve",
							buttonText: "Approve My Commissions"
						};
					}

				case "branch_manager_view_only":
					// "LoanOfficer" or "BothRequired" - BM viewing (view only)
					if (loApprovals.length > 0) {
						const personalizedMessage = formatPersonalizedApprovalMessage(
							loApprovals[0].lv_fullname,
							loApprovals[0].lv_emailaddress,
							window.PAGE_USEREMAIL,
							loApprovals[0].createdon
						);
						return {
							showViewOnly: true,
							message: personalizedMessage
						};
					} else {
						return {
							showViewOnly: true,
							message: `Awaiting approval by ${loanOfficerName}`
						};
					}

				case "loan_officer_view_only":
					// "BranchManager" config - LO viewing (view only)
					if (bmApprovals.length > 0) {
						const personalizedMessage = formatPersonalizedApprovalMessage(
							bmApprovals[0].lv_fullname,
							bmApprovals[0].lv_emailaddress,
							window.PAGE_USEREMAIL,
							bmApprovals[0].createdon
						);
						return {
							showViewOnly: true,
							message: personalizedMessage
						};
					} else {
						return {
							showViewOnly: true,
							message: "Awaiting branch manager approval"
						};
					}

				case "branch_manager_can_approve":
					// "BranchManager" config - BM can approve
					if (bmApprovals.length > 0) {
						const personalizedMessage = formatPersonalizedApprovalMessage(
							bmApprovals[0].lv_fullname,
							bmApprovals[0].lv_emailaddress,
							window.PAGE_USEREMAIL,
							bmApprovals[0].createdon
						);
						return {
							showApprovalComplete: true,
							message: personalizedMessage
						};
					} else {
						return {
							showApprovalRequired: true,
							showApprovalButton: true,
							message: `As Branch Manager, you are authorized to approve these commissions for ${loanOfficerName}`,
							buttonText: "Approve Commissions"
						};
					}

				case "loan_officer_own_both_required":
					// "BothRequired" config - LO viewing their own
					if (loApprovals.length > 0 && bmApprovals.length > 0) {
						const bmDate = formatApprovalDate(bmApprovals[0].createdon);
						const loDate = formatApprovalDate(loApprovals[0].createdon);
						return {
							showApprovalComplete: true,
							message: `Fully approved - Branch manager: ${bmApprovals[0].lv_fullname} on ${bmDate}, You: ${loDate}`
						};
					} else if (loApprovals.length > 0) {
						const loDate = formatApprovalDate(loApprovals[0].createdon);
						return {
							showViewOnly: true,
							message: `You approved these commissions on ${loDate}. Awaiting branch manager approval.`
						};
					} else if (bmApprovals.length > 0) {
						const bmDate = formatApprovalDate(bmApprovals[0].createdon);
						return {
							showApprovalRequired: true,
							showApprovalButton: true,
							message: `Branch manager approved on ${bmDate}. You can now provide your approval.`,
							buttonText: "Approve My Commissions"
						};
					} else {
						return {
							showApprovalRequired: true,
							showApprovalButton: true,
							message: "If you are satisfied with this commission report, click here to finalize and approve",
							buttonText: "Approve My Commissions"
						};
					}

				case "loan_officer_own_either":
					// "EitherOr" config - LO viewing their own
					if (bmApprovals.length > 0) {
						const personalizedMessage = formatPersonalizedApprovalMessage(
							bmApprovals[0].lv_fullname,
							bmApprovals[0].lv_emailaddress,
							window.PAGE_USEREMAIL,
							bmApprovals[0].createdon
						);
						return {
							showApprovalComplete: true,
							message: personalizedMessage
						};
					} else if (loApprovals.length > 0) {
						const personalizedMessage = formatPersonalizedApprovalMessage(
							loApprovals[0].lv_fullname,
							loApprovals[0].lv_emailaddress,
							window.PAGE_USEREMAIL,
							loApprovals[0].createdon
						);
						return {
							showApprovalComplete: true,
							message: personalizedMessage
						};
					} else {
						return {
							showApprovalRequired: true,
							showApprovalButton: true,
							message: "Either you or your branch manager can approve these commissions.",
							buttonText: "Approve My Commissions"
						};
					}

				case "branch_manager_can_approve_either":
					// "EitherOr" config - BM viewing (can approve)
					if (bmApprovals.length > 0) {
						const personalizedMessage = formatPersonalizedApprovalMessage(
							bmApprovals[0].lv_fullname,
							bmApprovals[0].lv_emailaddress,
							window.PAGE_USEREMAIL,
							bmApprovals[0].createdon
						);
						return {
							showApprovalComplete: true,
							message: personalizedMessage
						};
					} else if (loApprovals.length > 0) {
						const personalizedMessage = formatPersonalizedApprovalMessage(
							loApprovals[0].lv_fullname,
							loApprovals[0].lv_emailaddress,
							window.PAGE_USEREMAIL,
							loApprovals[0].createdon
						);
						return {
							showApprovalComplete: true,
							message: personalizedMessage
						};
					} else {
						return {
							showApprovalRequired: true,
							showApprovalButton: true,
							message: `As Branch Manager, you are authorized to approve these commissions for ${loanOfficerName}`,
							buttonText: "Approve Commissions"
						};
					}

				default:
					console.warn('APPROVAL: Unknown view mode:', viewMode);
					return {
						showViewOnly: true,
						message: 'Unknown approval configuration'
					};
			}

		} catch (error) {
			console.error('APPROVAL: Error checking approval status:', error);
			return {
				showViewOnly: true,
				message: 'Error checking approval status'
			};
		}
	}

	// Simple loan officer approval check - just checks if THIS loan officer has approved
	async function checkLoanOfficerApproval(officerCode, periodNo) {
		try {

			// Get all approval records for this officer and period
			const filterExpr = `$filter=lv_loanofficercode eq '${officerCode}' and lv_periodno eq ${periodNo}`;
			const approvalRecords = await apiGetRecords("lv_lvcompcommissionapprovals", filterExpr);

			if (!approvalRecords || !Array.isArray(approvalRecords) || approvalRecords.length === 0) {
				return { hasApproved: false, message: 'These commissions are awaiting your approval.' };
			}

			// Check if there's a loan officer approval
			const loApprovals = approvalRecords.filter(rec => rec.lv_webrole === 'Loan Officer');

			if (loApprovals.length > 0) {
				const approvalDate = formatApprovalDate(loApprovals[0].createdon);
				return { 
					hasApproved: true, 
					message: `You approved these commissions on ${approvalDate}.` 
				};
			} else {
				return { hasApproved: false, message: 'These commissions are awaiting your approval.' };
			}

		} catch (error) {
			return { hasApproved: false, message: 'These commissions are awaiting your approval.' };
		}
	}

	// Bulk approval functions have been moved to the /Branch page

	async function btnApproveClick() {

		addLoanOfficerToolTip(" (v3181502)")

		const cardCommTotalAsFormattedString = $("#cardCommTotal").text(); // the value from the 'Total' card

		const qText = 
			"<div>" + 
				"<div style='margin-bottom: 15px;'>On pressing 'Confirm', your approval of these commissions will be logged:</div>" + 

				"<div style='margin-left: 20px; margin-bottom: 10px;'>" + 
					"<table class='table-responsive'>" + 
						"<tr><td class='p-3'>Amount:</td><td class='p-1'><b>" + cardCommTotalAsFormattedString + "</b></td></tr>" +
						"<tr><td class='p-3'>Period:</td><td class='p-1'><b>" + window.PAGE_UISelPeriodCode + "</b></td></tr>" +
					"</table>" + 
				"</div>" + 

				"<div style='margin-bottom: 10px;'>An email confirmation will be sent to <b>" + window.PAGE_USEREMAIL + "</b></div>" + 

				"<div style='margin-bottom: 30px;'>Are you sure you are ready to approve your commissions?</div>" + 

				"<div>Press the 'Confirm' button to proceed</div>" + 
			"</div>";

		var userChoice =  await askQuestion(qText, btn1Text = "Confirm", btn2Text = "Cancel");

		if (userChoice != "Confirm") {
			return;
		}

		$('#btnApprove').hide();

		const $spn = $('#spanApprove');

		$spn.html('Please wait, recording your appproval... <span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>');

		const subject = "Commissions approved: Period " + window.PAGE_UISelPeriodCode;
		const body = "This email is to confirm that you approved commissions in the amount " + cardCommTotalAsFormattedString + " for period: " + window.PAGE_UISelPeriodCode;

		await sendEmail("Commission Approve", subject, body, window.PAGE_USEREMAIL, window.PAGE_LOCODE_BEINGVIEWED, window.PAGE_UISelPeriodCode, "", false, window.PAGE_UISelPeriodNo);

		{% comment %} Enhanced approval record creation for sophisticated approval system {% endcomment %} 
		// Determine approval role based on user permissions and viewing context
		const isBranchManager = {% if is_BranchManager %}true{% else %}false{% endif %};
		const canApproveCommissions = {% if canApproveCommissions %}true{% else %}false{% endif %};
		const isMyOwnCommissions = "{{user.lv_loanofficer.id}}" === "{{sqRecLOBeingViewed.lv_lvcomploanofficerid}}";

		let approvalRole = "Unknown";
		let branchCode = "{{sqRecLOBeingViewed.lv_branch.lv_code}}"; // Use branch code from loan officer record

		if (canApproveCommissions && !isMyOwnCommissions) {
			// Branch manager approving someone else's commissions
			approvalRole = "Branch Manager";
		} else if (isMyOwnCommissions) {
			// Loan officer approving their own commissions
			approvalRole = "Loan Officer";
		} else {
			console.warn('Unclear approval context - user cannot approve commissions and not approving own commissions');
			approvalRole = "Loan Officer"; // Default fallback
		}

		console.log('DEBUG APPROVAL: Role determination:', {
			isBranchManager: isBranchManager,
			canApproveCommissions: canApproveCommissions,
			isMyOwnCommissions: isMyOwnCommissions,
			approvalRole: approvalRole,
			branchCode: branchCode
		});

		const oPostAppr = {
			"lv_amount": safeStringToNumeric(cardCommTotalAsFormattedString),
			"lv_amountdisplayedtouser": cardCommTotalAsFormattedString,
			"lv_branchcode": "", // Leave blank for loan officer approvals
			"lv_emailaddress": window.PAGE_USEREMAIL,
			"lv_fullname" : window.PAGE_USERNAME,
			"lv_loanofficercode": window.PAGE_LOCODE_BEINGVIEWED,
			"lv_periodcode": window.PAGE_UISelPeriodCode,
			"lv_webrole": approvalRole,
			"lv_periodno": window.PAGE_UISelPeriodNo
		};

		try {
			const apiResponse = await apiCall("/_api/lv_lvcompcommissionapprovals", "POST", oPostAppr, true);
		} catch (error) {
			console.error('API call failed::', error);
			$spn.html("Error: Failed to record approval. Please try again or contact support.");
			$('#btnApprove').show();
			return;
		}

		await delay(2);

		writeToLogTable("ApproveEnd", "By: {{user.fullname}}", "PeriodNo", window.PAGE_UISelPeriodNo, "LoanOfficerCode", window.PAGE_LOCODE_BEINGVIEWED);

		$spn.html("Your approval has been recorded successfully");
	}

	// Helper function to update approval button for partial approval states
	function updateApprovalButtonForPartialStatus(statusDetails) {
		const approvalType = "{{sqApprovalType}}";
		const isUserDirectLO = "{{user.lv_loanofficer.id}}" === "{{sqRecLOBeingViewed.lv_lvcomploanofficerid}}";
		const isBranchManager = {{is_BranchManager}};
		const canApproveCommissions = {{canApproveCommissions}};
		const currentUser = "{{user.fullname}}";
		const officerName = "{{sqRecLOBeingViewed.lv_name}}";

		console.log('DEBUG: updateApprovalButtonForPartialStatus called with:', statusDetails);
		console.log('DEBUG: approvalType:', approvalType, 'isUserDirectLO:', isUserDirectLO, 'isBranchManager:', isBranchManager, 'canApproveCommissions:', canApproveCommissions);

		let buttonText = "Approve";
		let messageText = "";

		if (approvalType === "BothRequired") {
			// Parse which approval exists based on the exact messages from checkExistingApproval function
			// Format: "Partial approval - [Name] approved on [date]. Loan officer approval still required."
			// Format: "Partial approval - Loan officer approved on [date]. Branch manager approval still required."
			const bmApprovalExists = statusDetails.includes('Partial approval -') && statusDetails.includes('Loan officer approval still required');
			const loApprovalExists = statusDetails.includes('Partial approval - Loan officer approved on') && statusDetails.includes('Branch manager approval still required');

			console.log('DEBUG: BothRequired mode - bmApprovalExists:', bmApprovalExists, 'loApprovalExists:', loApprovalExists);
			console.log('DEBUG: Full status details:', statusDetails);

			if (bmApprovalExists && !loApprovalExists) {
				// Branch manager has approved, need loan officer approval
				if (isUserDirectLO) {
					messageText = `Branch manager approval completed. As the loan officer, you can now provide your approval.`;
					buttonText = "Approve My Commissions";
				} else {
					messageText = `Branch manager approval completed. Loan officer approval for ${officerName} is still required.`;
					buttonText = "Cannot Approve (Loan Officer Required)";
					$('#btnApprove').prop('disabled', true);
				}
			} else if (loApprovalExists && !bmApprovalExists) {
				// Loan officer has approved, need branch manager approval
				if (canApproveCommissions) {
					messageText = `Loan officer approval completed. As branch manager, you can now provide your approval for ${officerName}.`;
					buttonText = "Approve as Branch Manager";
				} else {
					messageText = `Loan officer approval completed. Branch manager approval for ${officerName} is still required.`;
					buttonText = "Cannot Approve (Branch Manager Required)";
					$('#btnApprove').prop('disabled', true);
				}
			}
		} else {
			// For other approval types with partial states, use appropriate messaging
			if (isUserDirectLO) {
				messageText = "You can approve your own commissions.";
				buttonText = "Approve My Commissions";
			} else if (canApproveCommissions) {
				messageText = `As manager, you can approve these commissions for ${officerName}.`;
				buttonText = "Approve Commissions";
			}
		}

		console.log('DEBUG: Setting messageText:', messageText, 'buttonText:', buttonText);

		// Update the UI elements
		$('#spanApprove').html(messageText);
		$('#btnApprove').val(buttonText);
	}

	// Helper function to reset approval button to default state
	function resetApprovalButtonToDefault() {
		const isUserDirectLO = "{{user.lv_loanofficer.id}}" === "{{sqRecLOBeingViewed.lv_lvcomploanofficerid}}";
		const officerName = "{{sqRecLOBeingViewed.lv_name}}";

		console.log('DEBUG: resetApprovalButtonToDefault called');

		// Simple approval messaging - no branch manager status info
		if (isUserDirectLO) {
			$('#spanApprove').html("If you are satisfied with this commission report, click here to approve");
			$('#btnApprove').val("Approve My Commissions");
		} else {
			$('#spanApprove').html(`As manager, you can approve these commissions for ${officerName}`);
			$('#btnApprove').val("Approve Commissions");
		}

		// Re-enable button in case it was disabled
		$('#btnApprove').prop('disabled', false);
	}

	async function onPageLoad() {
		try {
			// SKIP approval check for Administrators - they never approve commissions
			const isAdmin = window.PAGE_Roles?.isAdmin || false;
			if (isAdmin) {
				console.log('APPROVAL: Skipping approval check - user is Administrator');
				$('#approvalLoading').hide();
				$('#approvalComplete').hide();
				$('#approvalRequired').hide();
				$('#approvalViewOnly').hide();
				return;
			}

			// SKIP approval check if no loan officer selected yet (on initial page load)
			let officerIdentifier = window.PAGE_LOCODE_BEINGVIEWED;
			let useOfficerCode = true;

			if (!officerIdentifier || officerIdentifier === '') {
				// Try fallback to ID
				officerIdentifier = window.PAGE_LOID_BEINGVIEWED;
				useOfficerCode = false;

				// If still empty, no loan officer selected yet - skip approval check silently
				if (!officerIdentifier || officerIdentifier === '') {
					console.log('APPROVAL: Skipping approval check - no loan officer selected yet');
					$('#approvalLoading').hide();
					$('#approvalComplete').hide();
					$('#approvalRequired').hide();
					$('#approvalViewOnly').hide();
					return;
				}
			}

			console.log('APPROVAL: Checking approval status for', useOfficerCode ? 'officer code' : 'officer ID', ':', officerIdentifier);

			// Show loading state
			$('#approvalLoading').show();
			$('#approvalComplete').hide();
			$('#approvalRequired').hide();
			$('#approvalViewOnly').hide();

			// Use new sophisticated approval checking
			const approvalStatus = await checkSophisticatedApprovalStatus(
				officerIdentifier,
				window.PAGE_UISelPeriodNo,
				useOfficerCode
			);

			console.log('APPROVAL: Result:', approvalStatus);

			// Hide loading
			$('#approvalLoading').hide();

			// Display appropriate section based on result
			if (approvalStatus.showApprovalComplete) {
				$('#approvalStatusMessage').html(approvalStatus.message);
				$('#approvalComplete').show();
			} else if (approvalStatus.showApprovalRequired) {
				$('#spanApprove').html(approvalStatus.message);
				if (approvalStatus.showApprovalButton) {
					$('#btnApprove').val(approvalStatus.buttonText || 'Approve');
					$('#btnApprove').show();
				} else {
					$('#btnApprove').hide();
				}
				$('#approvalRequired').show();
			} else if (approvalStatus.showViewOnly) {
				$('#viewOnlyStatusMessage').html(approvalStatus.message);
				$('#approvalViewOnly').show();
			}

		} catch (error) {
			console.error("APPROVAL: Error checking approval status:", error);
			$('#approvalLoading').hide();
			$('#approvalViewOnly').show();
			$('#viewOnlyStatusMessage').html('Error loading approval status. Please refresh the page.');
		}
	}

	document.addEventListener("LVGlobalDOCReady", onPageLoad);

	// DEBUG FUNCTION: Manual approval record verification
	window.debugCheckApprovalRecords = async function() {
		try {
			console.log('=== MANUAL APPROVAL CHECK DEBUG ===');
			console.log('Current officer code:', window.PAGE_LOCODE_BEINGVIEWED);
			console.log('Current period:', window.PAGE_UISelPeriodNo);

			// Check with exact same query as individual check
			const individualQuery = `$filter=lv_loanofficercode eq '${window.PAGE_LOCODE_BEINGVIEWED}' and lv_periodno eq ${window.PAGE_UISelPeriodNo}`;
			console.log('Individual query:', individualQuery);
			const individualResult = await apiGetRecord("lv_lvcompcommissionapprovals", individualQuery);
			console.log('Individual query result:', individualResult);

			// FALLBACK: Try using loan officer ID if code is empty (debug the data mismatch)
			if (!window.PAGE_LOCODE_BEINGVIEWED || window.PAGE_LOCODE_BEINGVIEWED === '') {
				console.log('🔍 FALLBACK: Officer code is empty, trying ID-based query');
				const idQuery = `$filter=lv_loanofficerid eq '${window.PAGE_LOID_BEINGVIEWED}' and lv_periodno eq ${window.PAGE_UISelPeriodNo}`;
				console.log('ID-based query:', idQuery);
				const idResult = await apiGetRecord("lv_lvcompcommissionapprovals", idQuery);
				console.log('ID-based query result:', idResult);
			}

			// Check with same query as bulk check
			const bulkQuery = `$filter=lv_loanofficercode eq '${window.PAGE_LOCODE_BEINGVIEWED}' and lv_periodno eq ${window.PAGE_UISelPeriodNo}`;
			console.log('Bulk query:', bulkQuery);
			const bulkResult = await apiGetRecord("lv_lvcompcommissionapprovals", bulkQuery);
			console.log('Bulk query result:', bulkResult);

			// Get ALL records for this period to see what exists
			const allQuery = `$filter=lv_periodno eq ${window.PAGE_UISelPeriodNo}`;
			console.log('All records query:', allQuery);
			const allResults = await apiGetRecords("lv_lvcompcommissionapprovals", allQuery);
			console.log('All approval records for period:', allResults);

		} catch (error) {
			console.error('Debug check failed:', error);
		}
	};

	console.log('DEBUG: Added window.debugCheckApprovalRecords() function. Call it from console to test.');
{% else %}
	// Not using approvals
{% endif %}

{% comment %} Clear unwanted query parameters for simple loan officers while preserving safe ones {% endcomment %}
{% if is_OnlyLoanOfficer == true %}
// Clear query parameters for simple loan officers but preserve period and debug parameters
if (window.location.search) {
	const currentParams = new URLSearchParams(window.location.search);
	const newParams = new URLSearchParams();

	// Preserve safe parameters
	const safeParams = ['period', 'dbg'];
	safeParams.forEach(param => {
		if (currentParams.has(param)) {
			newParams.set(param, currentParams.get(param));
		}
	});

	const newUrl = window.location.origin + window.location.pathname + 
		(newParams.toString() ? '?' + newParams.toString() : '');
	window.history.replaceState({}, document.title, newUrl);

	console.log('Cleaned URL for simple LO, preserved: ' + newParams.toString());
}
{% endif %}

</script>

<!-- Loan Officer Page -->


<!-- Last modified Sat Aug 30 12:12PM -->
<!-- Last modified Sun Aug 31 5:00PM -->
<!-- Last modified Tue Sep 02 10:36AM -->
<!-- Last modified Tue Sep 02 11:20AM -->
<!-- Last modified Wed Oct 01 3:16PM -->
<!-- Last modified Wed Oct 01 4:00PM -->
<!-- Last modified Thu Oct 02 12:15PM -->
<!-- Last modified Thu Oct 02 12:20PM -->
<!-- Last modified Mon Oct 06 3:20PM -->
<!-- Last modified Fri Oct 24 4:07PM -->","customcss":"/* Optional custom styling */
.select2-container--default .select2-selection--single {
	height: 34px;
	padding: 2px 12px;
	/* border: 1px solid #ccc; */
	border: 6px solid red;
	border-radius: 4px;
  }

  .select2-container--default .select2-selection--single .select2-selection__arrow {
	height: 32px;
  }

  .select2-container--default .select2-selection--single .select2-selection__rendered {
