	font-weight: bold;
  }","customjavascript":"
","displayorder":6,"enablerating":false,"enabletracking":false,"excludefromsearch":false,"hiddenfromsitemap":true,"isroot":false,"pagetemplateid":"cd587cbe-a61f-4c11-a750-6d0235a784ef","parentpageid":"362995e0-7dc5-4bbf-9595-062f468d2d44","partialurl":"Loan-Officer","publishingstateid":"2177b470-e9b1-4c6b-8f73-91dc8f4d21e9","rootwebpageid":"6249e2f5-2a59-722d-a8fb-447db5b6beca","sharedpageconfiguration":false,"summary":"<p>This is a sample landing page designed to be a starting point for your website</p>
","title":"Loan Officer"}

powerpagecomponent.searchcontent:
Loan Officer<!-- Last modified Fri Oct 24 4:07PM -->
<!-- Last modified Mon Oct 06 3:20PM -->
<!-- Last modified Thu Oct 02 12:20PM -->
<!-- Last modified Thu Oct 02 12:15PM -->
<!-- Last modified Wed Oct 01 4:00PM -->
<!-- Last modified Wed Oct 01 3:16PM -->
<!-- Last modified Tue Sep 02 11:20AM -->
<!-- Last modified Tue Sep 02 10:36AM -->
<!-- Last modified Sun Aug 31 5:00PM -->
<!-- Last modified Sat Aug 30 12:12PM -->

<!-- Loan Officer Page -->

{% comment %} ~LoanOfficerPage PERFORMANCE OPTIMIZATION: Check if loan officer is specified to suppress unnecessary queries {% endcomment %}
{% assign hasLoanOfficerParam = false %}
{% if request.params.officer and request.params.officer != "" and request.params.officer != "all" %}
	{% assign hasLoanOfficerParam = true %}
{% endif %}

{% include 'snippet' snippet_name:'FetchXML - SetupQuery' %}

{%- comment -%} NOTE: Exclusions are now handled via userExclusionLOList from SetupQuery {%- endcomment -%}

{% comment %} Run period filtering query if officer param exists OR if user is simple loan officer {% endcomment %}
{% if hasLoanOfficerParam or is_OnlyLoanOfficer %}
	{% include 'snippet' snippet_name:'FetchXML - BranchQuery' %}

	{% comment %} PERIOD FILTERING: Get distinct periods where selected loan officer has commission data {% endcomment %}
	{% fetchxml periodsWithData %}
		<fetch aggregate="true">
			<entity name="lv_lvcompcommission">
				<attribute name="lv_periodno" alias="period_number" groupby="true" />
				<filter type="and">
					<condition attribute="lv_xloanofficercode" operator="eq" value="{{sqRecLOBeingViewed.lv_code}}" />
				</filter>
			</entity>
		</fetch>
	{% endfetchxml %}

		{% comment %} DEBT BALANCE: Get debt log entries server-side, pass to JavaScript for math {% endcomment %}
	{%- fetchxml debtLogEntries -%}
		<fetch>
			<entity name="lv_debtlogvalueentry">
				<attribute name="lv_identifiercode" />
				<attribute name="lv_entrydate" />
				<attribute name="lv_amount" />
				<attribute name="lv_description" />
				<filter type="and">
					<condition attribute="lv_loanofficercode" operator="eq" value="{{sqRecLOBeingViewed.lv_code}}" />
				</filter>
				<order attribute="lv_entrydate" descending="true" />
			</entity>
		</fetch>
	{%- endfetchxml -%}
{% endif %}

{% comment %} Loan Officer page is accessible to ALL authenticated users {% endcomment %}
{% comment %} Security is handled by what loan officers they can see, not page access {% endcomment %}

{% if user %}

<div class="row sectionBlockLayout text-start" style="display: flex; flex-wrap: wrap; margin: 0px; min-height: auto; padding: 8px;">
    <div class="container" style="display: flex; flex-wrap: wrap;">
        <div class="col-lg-12 columnBlockLayout email-modal-container" style="flex-grow: 1; display: flex; flex-direction: column; min-width: 250px; word-break: break-word; padding: 16px; margin: 60px 0px;">


			{% if is_OnlyLoanOfficer %}
				<h1>
					{{sqRecLOBeingViewed.lv_name}}
					<span id=spanOfficerId class="d-none">({{sqRecLOBeingViewed.lv_lvcomploanofficerid}})</span>
					<span id="spanPeriodCode" class="d-none">[{{sqRecUISelPeriod.lv_periodcode}}]
				</h1>

				<div class="admin-panel">
					<div style="display: flex; flex-direction: column; gap: 1rem;">
						{% include 'snippet' snippet_name:'Current Period Selection' %}
					</div>
				</div>
			{% else %}
				{% comment %}       include 'Loan Officer Dropdown', parmFoo: 'Asia', parmBar: 'Ursa'                        {% endcomment %} 

				<div class="admin-panel">
					<div style="display: flex; flex-direction: column; gap: 1rem;">

						{% comment %} Pass current selection to dropdown {% endcomment %}
						{% comment %} CRITICAL: Only set dropdown value if officer was explicitly selected via parameter {% endcomment %}
						{% if hasLoanOfficerParam %}
							{% if sqLOViewMode == "ALL_LOAN_OFFICERS" %}
								{% assign dropdownCurrentValue = "all" %}
							{% elsif sqRecLOBeingViewed.lv_lvcomploanofficerid %}
								{% assign dropdownCurrentValue = sqRecLOBeingViewed.lv_lvcomploanofficerid %}
							{% else %}
								{% assign dropdownCurrentValue = "" %}
							{% endif %}
						{% else %}
							{% assign dropdownCurrentValue = "" %}
						{% endif %}





						{%- unless is_OnlyLoanOfficer -%}
							{%- comment -%} PERFORMANCE FIX: Build dropdown list from userLoanOfficerList with exclusion filtering {%- endcomment -%}

							{%- comment -%} Build branchManagerOfficerCodes for dropdown population {%- endcomment -%}
							{%- assign branchManagerOfficerCodes = "" -%}
							{%- assign branchManagerOfficerNames = "" -%}
							{%- assign hasOfficers = false -%}

							{%- if is_admin -%}
								{%- comment -%} ADMIN: See ALL loan officers (no exclusions for admins) {%- endcomment -%}
								{%- if allLoanOfficers.results.entities -%}
									{%- for officer in allLoanOfficers.results.entities -%}
										{%- if officer.lv_code and officer.lv_code != blank -%}
											{%- if branchManagerOfficerCodes == "" -%}
												{%- assign branchManagerOfficerCodes = officer.lv_code -%}
											{%- else -%}
												{%- assign branchManagerOfficerCodes = branchManagerOfficerCodes | append: "|" | append: officer.lv_code -%}
											{%- endif -%}
											{%- assign hasOfficers = true -%}
										{%- endif -%}
									{%- endfor -%}
								{%- endif -%}
							{%- else -%}
								{%- comment -%} NON-ADMIN: Use userLoanOfficerList from SetupQuery with exclusion filtering {%- endcomment -%}
								{%- if userLoanOfficerList and userLoanOfficerList != "" and userLoanOfficerList != "|" -%}
									{%- comment -%} Extract codes from userLoanOfficerList (format: |name|code|name|code|) {%- endcomment -%}
									{%- assign parts = userLoanOfficerList | split: "|" -%}
									{%- assign partIndex = 0 -%}
									{%- for part in parts -%}
										{%- assign partIndex = partIndex | plus: 1 -%}
										{%- assign isEvenIndex = partIndex | modulo: 2 -%}
										{%- if isEvenIndex == 0 and part != "" -%}
											{%- comment -%} This is a loan officer code - check if excluded {%- endcomment -%}
											{%- assign loCode = part -%}
											{%- assign isExcluded = false -%}

											{%- comment -%} EXCLUSION CHECK: Only for branch managers using userExclusionLOList from SetupQuery {%- endcomment -%}
											{%- if is_BranchManager -%}
												{%- if userExclusionLOList != blank and userExclusionLOList != "" -%}
													{%- assign exclusionCheckString = "|" | append: loCode | append: "|" -%}
													{%- if userExclusionLOList contains exclusionCheckString -%}
														{%- assign isExcluded = true -%}
													{%- endif -%}
												{%- endif -%}
											{%- endif -%}

											{%- unless isExcluded -%}
												{%- if branchManagerOfficerCodes == "" -%}
													{%- assign branchManagerOfficerCodes = loCode -%}
												{%- else -%}
													{%- assign branchManagerOfficerCodes = branchManagerOfficerCodes | append: "|" | append: loCode -%}
												{%- endif -%}
												{%- assign hasOfficers = true -%}
											{%- endunless -%}
										{%- endif -%}
									{%- endfor -%}
								{%- endif -%}
							{%- endif -%}
						{%- endunless -%}

						{% comment %} CORRECT ORDER: Loan Officer dropdown FIRST {% endcomment %}
						{% include 'Loan Officer Dropdown', parmCurrentValue: dropdownCurrentValue %}

						{% comment %} CORRECT ORDER: Period dropdown SECOND {% endcomment %}
						{% include 'snippet' snippet_name:'Current Period Selection' %}







					</div>
				</div>
			{% endif %}

			{% if hasLoanOfficerParam or is_OnlyLoanOfficer %}
				{% include 'snippet' snippet_name:'Commission Filter' %}                               {% comment %} CENTRALIZED FILTERING: applies all permission and page-specific filters, sets cpCommCount, cpCommTotal, cpAdjuCount, cpAdjuTotal {% endcomment %}
				{% include 'snippet' snippet_name:'FetchXML - Current Period' %}
			{% else %}
				{% comment %} PERFORMANCE OPTIMIZATION: No loan officer selected - skip heavy data queries {% endcomment %}
				{% assign cpCommCount = 0 %}
				{% assign cpCommTotal = 0 %}
				{% assign cpAdjuCount = 0 %}
				{% assign cpAdjuTotal = 0 %}
				{% assign cpCommValueRowCount = 0 %}
				{% assign cpLoanCount = 0 %}
				{% assign cpLoanTotal = 0 %}
			{% endif %}


            {% if cpCommValueRowCount > 0 %}                            {% comment %}     cpCommValueRowCount is set in FetchXml-Current-Period    {% endcomment %} 

				<!-- JavaScript-based arithmetic to avoid DotLiquid bug -->
				{% assign rawSetting = settings['LV/NumApprovalPeriods'] %}
				{% if rawSetting == blank or rawSetting == empty or rawSetting == "" or rawSetting == nil %}
					{% assign rawSetting = "0" %}
				{% endif %}

				<script>
					// Calculate minPeriodAllowedForApprovals using JavaScript
					const settingNum = parseInt("{{rawSetting}}") || 0;
					const sqNum = parseInt("{{sqAcctgPeriodNo}}") || 0;
					const minPeriodAllowedForApprovals = sqNum - settingNum;

					// Store in window for use in conditional logic
					window.minPeriodAllowedForApprovals = minPeriodAllowedForApprovals;

					// Debug output
					console.log('JS Arithmetic:', {
						rawSetting: "{{rawSetting}}",
						settingNum: settingNum,
						sqAcctgPeriodNo: "{{sqAcctgPeriodNo}}",
						sqNum: sqNum,
						minPeriodAllowedForApprovals: minPeriodAllowedForApprovals
					});
				</script>

				<!-- Set Liquid variable from JavaScript calculation -->
				{% assign minPeriodAllowedForApprovals = -999 %}
				{% comment %} This will be overridden by JavaScript {% endcomment %}




				<script>
					// JavaScript-controlled approval section display
					document.addEventListener('DOMContentLoaded', function() {
						const sqUsingApprovals = {{sqUsingApprovals}};
						const sqRecUISelPeriodNo = {{sqRecUISelPeriod.lv_periodno}};
						const sqLOViewMode = "{{sqLOViewMode}}";
						const minPeriodAllowedForApprovals = window.minPeriodAllowedForApprovals;

						console.log('Approval Check:', {
							sqUsingApprovals: sqUsingApprovals,
							sqRecUISelPeriodNo: sqRecUISelPeriodNo,
							sqLOViewMode: sqLOViewMode,
							minPeriodAllowedForApprovals: minPeriodAllowedForApprovals
						});

						// Show or hide approval section based on conditions
						const approvalDiv = document.getElementById('approvalSectionWrapper');
						const condition1 = sqUsingApprovals === true;
						const condition2 = sqRecUISelPeriodNo >= minPeriodAllowedForApprovals;
						const condition3 = sqLOViewMode !== "ALL_LOAN_OFFICERS";
						const allConditionsMet = condition1 && condition2 && condition3;


						if (allConditionsMet) {
										approvalDiv.style.display = 'block';
						} else {
										approvalDiv.style.display = 'none';
						}
					});
				</script>

				<div id="approvalSectionWrapper" style="display: none;">
				{% comment %} This div will be shown/hidden by JavaScript {% endcomment %}


					<!-- Step 1: Check if user has direct LO assignment (yes we are using approvals) -->
					{% assign userHasDirectLO = false %}
					{% if user.lv_loanofficer.id %}
						{% if user.lv_loanofficer.id != blank %}
							{% if user.lv_loanofficer.id != "" %}
								{% assign userHasDirectLO = true %}
							{% endif %}
						{% endif %}
					{% endif %}

					<!-- Step 2: Check if we have a selected LO -->
					{% assign hasSelectedLO = false %}
					{% if sqRecLOBeingViewed.lv_lvcomploanofficerid %}
						{% if sqRecLOBeingViewed.lv_lvcomploanofficerid != blank %}
							{% if sqRecLOBeingViewed.lv_lvcomploanofficerid != "" %}
								{% assign hasSelectedLO = true %}
							{% endif %}
						{% endif %}
					{% endif %}

					<!-- Step 3: Check if LO IDs match -->
					{% assign loanOfficerMatch = false %}
					{% if userHasDirectLO == true %}
						{% if hasSelectedLO == true %}
							{% if user.lv_loanofficer.id == sqRecLOBeingViewed.lv_lvcomploanofficerid %}
								{% assign loanOfficerMatch = true %}
							{% endif %}
						{% endif %}
					{% endif %}

					<!-- APPROVAL LOGIC -->
					<!-- Determine if we should show approval section and what type -->
					{% assign showApprovalSection = false %}
					{% assign allowApprovalAction = false %}
					{% assign approvalViewMode = "none" %}

					<!-- Step 4: Determine approval view mode based on configuration and user role -->
					{% if sqApprovalType == "" or sqApprovalType == "None" %}
						{% assign approvalViewMode = "none" %}
					{% elsif sqApprovalType == "LoanOfficer" %}
						{% if loanOfficerMatch == true %}
							{% assign showApprovalSection = true %}
							{% assign allowApprovalAction = true %}
							{% assign approvalViewMode = "loan_officer_own" %}
						{% elsif canApproveCommissions == true %}
							{% assign showApprovalSection = true %}
							{% assign allowApprovalAction = false %}
							{% assign approvalViewMode = "branch_manager_view_only" %}
						{% endif %}
					{% elsif sqApprovalType == "BranchManager" %}
						{% if loanOfficerMatch == true %}
							{% assign showApprovalSection = true %}
							{% assign allowApprovalAction = false %}
							{% assign approvalViewMode = "loan_officer_view_only" %}
						{% elsif canApproveCommissions == true %}
							{% assign showApprovalSection = true %}
							{% assign allowApprovalAction = true %}
							{% assign approvalViewMode = "branch_manager_can_approve" %}
						{% endif %}
					{% elsif sqApprovalType == "BothRequired" %}
						{% if loanOfficerMatch == true %}
							{% assign showApprovalSection = true %}
							{% assign allowApprovalAction = true %}
							{% assign approvalViewMode = "loan_officer_own_both_required" %}
						{% elsif canApproveCommissions == true %}
							{% assign showApprovalSection = true %}
							{% assign allowApprovalAction = false %}
							{% assign approvalViewMode = "branch_manager_view_only" %}
						{% endif %}
					{% elsif sqApprovalType == "EitherOr" %}
						{% if loanOfficerMatch == true %}
							{% assign showApprovalSection = true %}
							{% assign allowApprovalAction = true %}
							{% assign approvalViewMode = "loan_officer_own_either" %}
						{% elsif canApproveCommissions == true %}
							{% assign showApprovalSection = true %}
							{% assign allowApprovalAction = true %}
							{% assign approvalViewMode = "branch_manager_can_approve_either" %}
						{% endif %}
					{% endif %}

					<!-- Set canApprove for compatibility -->
					{% assign canApprove = showApprovalSection %}


					<!-- lodd:appr00 -->
					{% if canApprove == true %}
						<!-- lodd:appr00.a -->
						<div id="divApproval" class="approval-section" style="margin: 20px 0;">
							<div id="approvalLoading">
								<div style="display: flex; align-items: center;">
									<span style="margin-right: 10px;">Checking approval status...</span>
									<div class="spinner-border spinner-border-sm" role="status">
										<span class="sr-only">Loading...</span>
									</div>
								</div>
							</div>

							<!-- Hidden data for JavaScript -->
							<script type="text/javascript">
								window.APPROVAL_VIEW_MODE = "{{approvalViewMode}}";
								window.ALLOW_APPROVAL_ACTION = {{allowApprovalAction}};
								window.LOAN_OFFICER_NAME = "{{sqRecLOBeingViewed.lv_name}}";
								window.IS_BRANCH_MANAGER = {{is_BranchManager}};
								window.CAN_APPROVE_COMMISSIONS = {{canApproveCommissions}};
								window.IS_OWN_COMMISSIONS = {% if user.lv_loanofficer.id == sqRecLOBeingViewed.lv_lvcomploanofficerid %}true{% else %}false{% endif %};
							</script>

							{% comment %}  Approved state (hidden initially)   {% endcomment %} 
							<div id="approvalComplete" style="display: none;">
								<div id="approvalStatusMessage" style="color: green; font-weight: bold; margin-bottom: 10px;">
									<!-- Status message will be populated by JavaScript -->
								</div>
							</div>

							{% comment %}   Not yet approved state (hidden initially)   {% endcomment %} 
							<div id="approvalRequired" style="display: none;">
								<div style="display: flex; align-items: center;">
									<span id="spanApprove" style="margin-left: 20px; margin-right: 10px; background-color: transparent;">
										<!-- Message will be populated by JavaScript based on approval mode -->
									</span>
									<input id="btnApprove" type="button" value="Approve" 
										onclick="return btnApproveClick();" class="btn" 
										style="background-color: var(--portalThemeColor10); color: var(--portalThemeColor5); border: none; border-radius: 8px; padding: 10px 15px; display: none;" />
								</div>
							</div>

							{% comment %}   View-only state for Branch Managers   {% endcomment %} 
							<div id="approvalViewOnly" style="display: none;">
								<div id="viewOnlyStatusMessage" style="color: #666; margin-bottom: 10px;">
									<!-- View-only status message will be populated by JavaScript -->
								</div>
							</div>
						</div>
					{% else %}
