					                    {% comment %} DEBT BALANCE - Server-side data passed to JavaScript for math {% endcomment %}
                    <!-- DEBUG:DEBTLOG: sqRecLOBeingViewed.lv_code="{{sqRecLOBeingViewed.lv_code}}" -->
                    <!-- DEBUG:DEBTLOG: debtLogEntries.results.entities.size={{debtLogEntries.results.entities.size}} -->
                    <!-- DEBUG:DEBTLOG: hasLoanOfficerParam={{hasLoanOfficerParam}} is_OnlyLoanOfficer={{is_OnlyLoanOfficer}} -->
                    <script>
                        // Server-rendered debt log entries (FetchXML query, no AJAX needed)
                        // Math (summing) is done in JavaScript to avoid Liquid arithmetic issues
                        // DEBUG: LO Code = "{{sqRecLOBeingViewed.lv_code}}", Entry count = {{debtLogEntries.results.entities.size | default: 0}}
                        window.DEBT_LOG_ENTRIES = [
                            {%- for entry in debtLogEntries.results.entities -%}
                            {
                                identifierCode: "{{ entry.lv_identifiercode }}",
                                date: "{{ entry.lv_entrydate | date: 'yyyy-MM-dd' }}",
                                amount: {{ entry.lv_amount | default: 0 }},
                                description: "{{ entry.lv_description | replace: '"', '\\"' | replace: '\n', ' ' | replace: '\r', '' }}"
                            }{%- unless forloop.last -%},{%- endunless -%}
                            {%- endfor -%}
                        ];
                        console.log('DEBT BALANCE: Server-rendered', window.DEBT_LOG_ENTRIES.length, 'entries');

                        /**
                         * GetDebtLogEntries - Returns server-rendered debt log entries (no AJAX)
                         * Data is fetched server-side via FetchXML query
                         * @returns {Array} Array of debt log entry objects
                         */
                        function GetDebtLogEntries() {
                            return window.DEBT_LOG_ENTRIES || [];
                        }

                        /**
                         * Calculate total from debt log entries
                         */
                        function calculateDebtBalanceTotal(entries) {
                            return entries.reduce((sum, entry) => sum + entry.amount, 0);
                        }

                        /**
                         * Format currency value
                         */
                        function formatDebtCurrency(amount) {
                            const formatted = new Intl.NumberFormat('en-US', {
                                style: 'currency',
                                currency: 'USD'
                            }).format(Math.abs(amount));

                            return amount < 0 ? '-' + formatted : formatted;
                        }

                        /**
                         * Format date for display
                         */
                        function formatDebtDate(dateStr) {
                            if (!dateStr) return '';
                            const date = new Date(dateStr + 'T00:00:00');
                            return date.toLocaleDateString('en-US', {
                                month: '2-digit',
                                day: '2-digit',
                                year: '2-digit'
                            });
                        }

                        /**
                         * Toggle detail panel visibility (card stays in grid)
                         */
                        function toggleDebtBalanceDetail() {
                            const detail = document.getElementById('debtBalanceDetail');

                            if (detail.style.display === 'none' || detail.style.display === '') {
                                detail.style.display = 'block';
                            } else {
                                detail.style.display = 'none';
                            }
                        }

                        /**
                         * Render debt balance card and detail table
                         * Uses server-rendered data (no AJAX), JavaScript does the math
                         */
                        function renderDebtBalance() {
                            const amountEl = document.getElementById('debtBalanceAmount');
                            const hintEl = document.getElementById('debtBalanceHint');

                            try {
                                const entries = GetDebtLogEntries();  // Sync - data is pre-loaded
                                const total = calculateDebtBalanceTotal(entries);  // JavaScript does the math

                                // Update card amount
                                amountEl.textContent = formatDebtCurrency(total);
                                if (total < 0) {
                                    amountEl.classList.add('negative');
                                } else {
                                    amountEl.classList.remove('negative');
                                }

                                // Update detail table
                                const tbody = document.getElementById('debtBalanceTableBody');
                                if (entries.length === 0) {
                                    tbody.innerHTML = '<tr><td colspan="4" style="text-align: center; color: #888;">No debt log entries found</td></tr>';
                                    hintEl.style.display = 'none';
                                } else {
                                    tbody.innerHTML = entries.map(entry => {
                                        const amountClass = entry.amount >= 0 ? 'amount-positive' : 'amount-negative';
                                        return `
                                            <tr>
                                                <td>${entry.identifierCode}</td>
                                                <td>${formatDebtDate(entry.date)}</td>
                                                <td style="text-align: right;" class="${amountClass}">${formatDebtCurrency(entry.amount)}</td>
                                                <td>${entry.description}</td>
                                            </tr>
                                        `;
                                    }).join('');
                                }

                                // Update detail total
                                const totalEl = document.getElementById('debtBalanceTotalDetail');
                                totalEl.textContent = formatDebtCurrency(total);
                                if (total < 0) {
                                    totalEl.classList.add('negative');
                                } else {
                                    totalEl.classList.remove('negative');
                                }

                            } catch (error) {
                                console.error('DEBT BALANCE: Error rendering:', error);
                                amountEl.textContent = 'Error';
                                amountEl.style.color = '#c0392b';
                            }
                        }

                        // Initialize debt balance on page load
                        // Data is already server-rendered, just need to calculate totals and render
                        document.addEventListener('DOMContentLoaded', function() {
                            renderDebtBalance();
                        });
                    </script>


